     1→export const classifyError = (error: unknown): { type: string; message: string } => {
     2→    let errorMessage: string;
     3→  
     4→    if (typeof error === "object" && error !== null) {
     5→      if ("message" in error) {
     6→        errorMessage = (error as Error).message;
     7→      } else {
     8→        errorMessage = "Unknown error";  
     9→      }
    10→    } else {
    11→      errorMessage = error?.toString() || "Unknown error";
    12→    }
    13→  
    14→    const businessErrors = [
    15→      "Customer not found",
    16→      "Contracted product not found",
    17→      "Promoção já contratada para o cliente",
    18→    ];
    19→  
    20→    if (businessErrors.some((msg) => errorMessage.includes(msg))) {
    21→      return { type: "business", message: errorMessage };
    22→    }
    23→  
    24→    if (errorMessage.includes("Erro na consulta da query") || errorMessage.includes("status: -1")) {
    25→      return { type: "system", message: errorMessage };
    26→    }
    27→  
    28→    return { type: "system", message: errorMessage };
    29→  };
